// ── Custom players Supabase ──────────────────────────────────────────────────
async function supaFetchCustomPlayers() {
  const res = await fetch(SUPA_URL + "/rest/v1/custom_players?select=name,game,league,role,team&order=name.asc", {
    headers: {"apikey": SUPA_KEY, "Authorization": "Bearer " + SUPA_KEY}
  });
  if(!res.ok) return null;
  return await res.json();
}
async function supaUpsertCustomPlayer(name, data) {
  await fetch(SUPA_URL + "/rest/v1/custom_players", {
    method: "POST",
    headers: {"apikey": SUPA_KEY, "Authorization": "Bearer " + SUPA_KEY, "Content-Type": "application/json", "Prefer": "resolution=merge-duplicates"},
    body: JSON.stringify({name: name.toLowerCase().trim(), game: data.game||"LoL", league: data.league||"", role: data.role||"", team: data.team||""})
  });
}
async function supaDeleteCustomPlayer(name) {
  await fetch(SUPA_URL + "/rest/v1/custom_players?name=eq." + encodeURIComponent(name.toLowerCase().trim()), {
    method: "DELETE",
    headers: {"apikey": SUPA_KEY, "Authorization": "Bearer " + SUPA_KEY}
  });
}
async function supaRenameCustomPlayer(oldName, newName, data) {
  await supaDeleteCustomPlayer(oldName);
  await supaUpsertCustomPlayer(newName, data);
}

async function supaFetch(path, opts={}) {
  const res = await fetch(SUPA_URL + path, {
    method: opts.method || "GET",
    headers: {
      "apikey": SUPA_KEY,
      "Authorization": "Bearer " + SUPA_KEY,
      "Content-Type": "application/json",
      "Prefer": opts.prefer || "",
    },
    body: opts.body,
  });
  const text = await res.text();
  if (!res.ok) throw new Error(text || String(res.status));
  try { return text ? JSON.parse(text) : null; } catch { return null; }
}

async function supaPullBets() {
  // Paginer pour dépasser la limite de 1000 de Supabase
  const limit = 1000;
  let all = [];
  let offset = 0;
  while(true) {
    const batch = await supaFetch(`/rest/v1/bets?select=id,player,description,overUnder,odds,stake,bookmaker,status,game,league,role,team,datetime,isHeadshot,isLive,mapTag,profit,tournament,splits&order=datetime.desc&limit=${limit}&offset=${offset}`);
    if(!batch || batch.length === 0) break;
    all = [...all, ...batch];
    if(batch.length < limit) break;
    offset += limit;
  }
  return all.map(b=>({
    ...b,
    splits:b.splits?JSON.parse(b.splits):undefined
  }));
}

async function supaPushBets(bets) {
  const rows = bets.map(({id,player,description,overUnder,odds,stake,bookmaker,
    status,game,league,role,team,datetime,isHeadshot,isLive,mapTag,profit,tournament,splits})=>
    ({id,player,description,overUnder,odds,stake,bookmaker,status,game,league,role,
      team,datetime,isHeadshot:!!isHeadshot,isLive:!!isLive,mapTag,profit,tournament,
      splits:splits&&splits.length>0?JSON.stringify(splits):null}));
  // Chunk en 500
  for(let i=0;i<rows.length;i+=500){
    await supaFetch("/rest/v1/bets",{
      method:"POST",
      body:JSON.stringify(rows.slice(i,i+500)),
      prefer:"resolution=merge-duplicates",
    });
  }
}

async function supaDeleteAllBets() {
  // Supprimer tous les enregistrements (neq trick car Supabase exige un filtre)
  await supaFetch("/rest/v1/bets?id=neq.0",{method:"DELETE"});
  await supaFetch("/rest/v1/bets?id=eq.0",{method:"DELETE"});
}
async function supaDeleteOneBet(id) {
  await supaFetch("/rest/v1/bets?id=eq."+id,{method:"DELETE"});
}
async function supaDeleteManyBets(ids) {
  if(!ids||!ids.length)return;
  await supaFetch("/rest/v1/bets?id=in.("+ids.join(",")+")",{method:"DELETE"});
}

